import { Spinner } from "@carbon/react";
import { useEffect, useRef, useState } from "react";
import { useDocumentTemplate } from "./context";

const PREVIEW_DEBOUNCE_MS = 500;

/**
 * Server-rendered preview. The PDF is generated by the `.preview` route (Node,
 * where @react-pdf/renderer's Buffer/stream deps exist) and shown in the
 * browser's native PDF viewer via an iframe. No client-side react-pdf, no
 * polyfills, and the preview is byte-identical to the real document route.
 */
export function TemplatePreview({ previewPath }: { previewPath: string }) {
  const {
    blocks,
    theme,
    settings,
    headerSectionId,
    footerSectionId,
    sections,
    previewId
  } = useDocumentTemplate();
  const [url, setUrl] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const urlRef = useRef<string | null>(null);

  // biome-ignore lint/correctness/useExhaustiveDependencies: `sections` is intentionally a dep so editing a header/footer section re-renders the preview.
  useEffect(() => {
    const controller = new AbortController();
    const handle = setTimeout(async () => {
      setIsLoading(true);
      try {
        const formData = new FormData();
        formData.append("blocks", JSON.stringify(blocks));
        formData.append("theme", JSON.stringify(theme));
        formData.append("settings", JSON.stringify(settings));
        formData.append("headerSectionId", headerSectionId ?? "");
        formData.append("footerSectionId", footerSectionId ?? "");
        if (previewId) formData.append("previewId", previewId);
        const response = await fetch(previewPath, {
          method: "post",
          body: formData,
          signal: controller.signal
        });
        if (!response.ok) return;
        const blob = await response.blob();
        const nextUrl = URL.createObjectURL(blob);
        if (urlRef.current) URL.revokeObjectURL(urlRef.current);
        urlRef.current = nextUrl;
        setUrl(nextUrl);
      } catch (error) {
        if (!controller.signal.aborted) console.error(error);
      } finally {
        if (!controller.signal.aborted) setIsLoading(false);
      }
    }, PREVIEW_DEBOUNCE_MS);

    return () => {
      controller.abort();
      clearTimeout(handle);
    };
    // `sections` is included so editing a header/footer section (which the
    // preview route resolves server-side) retriggers a fresh render.
  }, [
    blocks,
    theme,
    settings,
    headerSectionId,
    footerSectionId,
    sections,
    previewId,
    previewPath
  ]);

  // Revoke the last object URL on unmount.
  useEffect(
    () => () => {
      if (urlRef.current) URL.revokeObjectURL(urlRef.current);
    },
    []
  );

  return (
    <div className="relative mx-auto flex h-full w-full max-w-3xl flex-col overflow-hidden rounded-lg border bg-card shadow-sm">
      {url && (
        <iframe
          key={url}
          src={url}
          title="Document preview"
          className="block h-full w-full grow border-none"
        />
      )}
      {isLoading && (
        <div className="absolute inset-0 flex items-center justify-center bg-background/60 backdrop-blur-[1px]">
          <Spinner className="size-6" />
        </div>
      )}
    </div>
  );
}
